SELECT SUM(amount * cost_per_unit) AS total_fermentable_cost
FROM fermentables
WHERE recipe_id = 1;

SELECT ingredient_name 
FROM fermentables 
WHERE type = 'malt' AND cost_per_unit < 1.0;

SELECT name, style, volume, estimated_cost
FROM recipes
WHERE recipe_id = (SELECT recipe_id FROM recipes ORDER BY estimated_cost DESC LIMIT 1);

SELECT AVG(analytics.average_rating) AS avg_rating_of_favorites
FROM analytics
JOIN favorites ON analytics.recipe_id = favorites.recipe_id;

SELECT estimated_cost AS total_estimated_cost
FROM recipes
WHERE recipe_id = 1;

SELECT COUNT(DISTINCT recipe_id) AS public_recipe_count
FROM recipes
WHERE is_public = 1;

SELECT hop_name
FROM hops
WHERE alpha_acids > 10;
